"""Агент text2sql на tool calling через OpenAI-совместимый API."""

from __future__ import annotations

import datetime as _dt
import json
import sys
from dataclasses import dataclass, field
from typing import Any, Callable

from openai import OpenAI

from text2sql.config import AppConfig, load_config
from text2sql.db import OracleClient, QueryResult, SQLValidationError, validate_select
from text2sql.schema import compact_schema_text, describe_table
from text2sql.tools import TOOLS
from text2sql.validate import validate_result as _validate_result


SYSTEM_PROMPT = """Ты — ассистент-аналитик для Oracle XE базы корпоративного банка.
Твоя задача: на вопрос пользователя на естественном языке вернуть фактический ответ \
с реальными цифрами из БД client_product.

ПРАВИЛА работы:
1. Сначала пойми, какие поля нужны. Если нужна более полная семантика — вызови `inspect_schema`.
2. Сформируй корректный Oracle SQL и вызови `execute_sql`. Используй только SELECT/WITH.
3. Учитывай агрегационные правила: `aggregation_between_clients` — как агрегировать между клиентами \
(обычно SUM), `aggregation_between_month` — как агрегировать между месяцами (для остатков AVG, \
для оборотов и P&L — SUM).
4. ЗАПРЕЩЕНО суммировать поле с его составляющими ('ИТОГОВОЕ ПОЛЕ' в описании).
5. Если результат вызывает сомнения (пусто, странные значения, выглядит занижено/завышено) — \
вызови `validate_result` с явными expectations, или сформируй уточняющий SQL.
6. Когда получены и проверены цифры — вызови `final_answer` с человеческим ответом, \
содержащим конкретные числа, период, единицы измерения и краткую интерпретацию.
7. Числа форматируй с разделителями тысяч; денежные суммы — в рублях с пометкой "руб." \
или "млн руб./млрд руб." если уместно.
8. Никогда не выдумывай данные. Если SQL вернул пусто — честно скажи об этом.
9. Все date-литералы пиши в формате Oracle: DATE 'YYYY-MM-DD'. Закрытые месяцы — последний день месяца.

Доступная таблица:
"""


@dataclass
class AgentTrace:
    steps: list[dict[str, Any]] = field(default_factory=list)

    def log(self, kind: str, payload: Any) -> None:
        self.steps.append(
            {
                "ts": _dt.datetime.now().isoformat(timespec="seconds"),
                "kind": kind,
                "payload": payload,
            }
        )


@dataclass
class AgentResult:
    answer: str
    supporting_data: dict[str, Any] | None
    sql_executed: list[str]
    trace: AgentTrace
    last_result: QueryResult | None


def _tool_log(msg: str) -> None:
    print(f"[agent] {msg}", file=sys.stderr, flush=True)


class Text2SQLAgent:
    """Агент с tool calling: модель сама выбирает следующий шаг."""

    def __init__(
        self,
        config: AppConfig | None = None,
        oracle_client: OracleClient | None = None,
        openai_client: OpenAI | None = None,
        log: Callable[[str], None] | None = None,
    ):
        self.cfg = config or load_config()
        self.oracle = oracle_client or OracleClient(self.cfg.oracle, max_rows=self.cfg.max_rows)
        self.client = openai_client or OpenAI(
            base_url=self.cfg.llm.base_url,
            api_key=self.cfg.llm.api_key,
        )
        self.log = log or _tool_log
        # текущее состояние, обновляется между шагами цикла
        self._last_result: QueryResult | None = None
        self._sql_history: list[str] = []

    # ---------- tool implementations ----------

    def _t_inspect_schema(self, args: dict[str, Any]) -> dict[str, Any]:
        table = args.get("table") or "client_product"
        return describe_table(table)

    def _t_execute_sql(self, args: dict[str, Any]) -> dict[str, Any]:
        sql = args.get("sql") or ""
        max_rows = args.get("max_rows")
        try:
            cleaned = validate_select(sql)
        except SQLValidationError as exc:
            return {"error": "validation_error", "message": str(exc)}
        try:
            result = self.oracle.execute_select(
                cleaned, max_rows=int(max_rows) if max_rows else None
            )
        except SQLValidationError as exc:
            return {"error": "validation_error", "message": str(exc)}
        except Exception as exc:  # oracledb / network errors
            return {
                "error": "execution_error",
                "message": f"{type(exc).__name__}: {exc}",
            }
        self._last_result = result
        self._sql_history.append(cleaned)
        out = result.to_dict()
        # ограничим размер ответа модели: для крупных результатов оставим первые N строк
        if len(out["rows"]) > 50:
            out["rows_preview"] = out["rows"][:50]
            out["rows"] = out["rows_preview"]
            out["note"] = "Показаны первые 50 строк (полный результат сохранён в state агента)."
        return out

    def _t_validate_result(self, args: dict[str, Any]) -> dict[str, Any]:
        if self._last_result is None:
            return {
                "ok": False,
                "issues": ["Нет результата для валидации — вызови сначала execute_sql"],
            }
        return _validate_result(self._last_result, args.get("expectations") or {})

    def _dispatch(self, name: str, args: dict[str, Any]) -> dict[str, Any]:
        if name == "inspect_schema":
            return self._t_inspect_schema(args)
        if name == "execute_sql":
            return self._t_execute_sql(args)
        if name == "validate_result":
            return self._t_validate_result(args)
        return {"error": "unknown_tool", "message": f"Неизвестный tool: {name}"}

    # ---------- agent loop ----------

    def _build_messages(self, question: str) -> list[dict[str, Any]]:
        system = SYSTEM_PROMPT + "\n" + compact_schema_text("client_product")
        return [
            {"role": "system", "content": system},
            {"role": "user", "content": question},
        ]

    def answer(self, question: str) -> AgentResult:
        trace = AgentTrace()
        messages = self._build_messages(question)
        self._last_result = None
        self._sql_history = []

        max_steps = self.cfg.max_agent_steps
        final_text: str | None = None
        final_data: dict[str, Any] | None = None

        for step in range(1, max_steps + 1):
            self.log(f"step {step}: calling LLM")
            try:
                resp = self.client.chat.completions.create(
                    model=self.cfg.llm.sql_model,
                    messages=messages,
                    tools=TOOLS,
                    tool_choice="auto",
                    temperature=self.cfg.temperature,
                )
            except Exception as exc:
                trace.log("llm_error", {"error": f"{type(exc).__name__}: {exc}"})
                raise RuntimeError(f"Ошибка вызова LLM: {exc}") from exc

            msg = resp.choices[0].message
            tool_calls = getattr(msg, "tool_calls", None) or []

            assistant_msg: dict[str, Any] = {"role": "assistant"}
            if msg.content:
                assistant_msg["content"] = msg.content
            if tool_calls:
                assistant_msg["tool_calls"] = [
                    {
                        "id": tc.id,
                        "type": "function",
                        "function": {
                            "name": tc.function.name,
                            "arguments": tc.function.arguments or "{}",
                        },
                    }
                    for tc in tool_calls
                ]
            else:
                # Некоторые модели могут не сделать tool call и просто выдать текст.
                # Тогда трактуем content как финальный ответ.
                assistant_msg["content"] = msg.content or ""
            messages.append(assistant_msg)

            if not tool_calls:
                final_text = msg.content or ""
                trace.log("no_tool_calls", {"content_preview": final_text[:200]})
                break

            terminate = False
            for tc in tool_calls:
                name = tc.function.name
                raw_args = tc.function.arguments or "{}"
                try:
                    args = json.loads(raw_args) if raw_args else {}
                except json.JSONDecodeError:
                    args = {}

                if name == "final_answer":
                    final_text = str(args.get("text") or "").strip()
                    sd = args.get("supporting_data")
                    final_data = sd if isinstance(sd, dict) else None
                    trace.log("final_answer", {"text": final_text})
                    messages.append(
                        {
                            "role": "tool",
                            "tool_call_id": tc.id,
                            "content": json.dumps({"ok": True}, ensure_ascii=False),
                        }
                    )
                    terminate = True
                    continue

                self.log(f"step {step}: tool {name}({list(args.keys())})")
                try:
                    result = self._dispatch(name, args)
                except Exception as exc:
                    result = {
                        "error": "tool_exception",
                        "message": f"{type(exc).__name__}: {exc}",
                    }
                trace.log(
                    "tool_call",
                    {
                        "name": name,
                        "args": args,
                        "result_preview": _preview(result),
                    },
                )
                messages.append(
                    {
                        "role": "tool",
                        "tool_call_id": tc.id,
                        "content": json.dumps(result, ensure_ascii=False, default=str),
                    }
                )

            if terminate:
                break

        if final_text is None:
            # Сделаем последнюю попытку: попросим модель сформировать ответ без tools.
            self.log("forcing final answer (max_steps reached)")
            messages.append(
                {
                    "role": "user",
                    "content": (
                        "Лимит шагов исчерпан. Сформулируй итоговый ответ на основе уже "
                        "полученных данных одним сообщением, без вызова инструментов."
                    ),
                }
            )
            try:
                resp = self.client.chat.completions.create(
                    model=self.cfg.llm.response_model,
                    messages=messages,
                    temperature=self.cfg.temperature,
                )
                final_text = resp.choices[0].message.content or "(пустой ответ модели)"
            except Exception as exc:
                final_text = f"Не удалось получить ответ от модели: {exc}"

        return AgentResult(
            answer=final_text or "",
            supporting_data=final_data,
            sql_executed=list(self._sql_history),
            trace=trace,
            last_result=self._last_result,
        )


def _preview(obj: Any, limit: int = 400) -> str:
    try:
        s = json.dumps(obj, ensure_ascii=False, default=str)
    except Exception:
        s = repr(obj)
    return s if len(s) <= limit else s[:limit] + "...(truncated)"


def answer_question(question: str, config: AppConfig | None = None) -> AgentResult:
    """Удобный shortcut: создать агента и получить ответ."""
    agent = Text2SQLAgent(config=config)
    return agent.answer(question)

"""Клиент Oracle на oracledb. Выполнение read-only SELECT-запросов."""

from __future__ import annotations

import datetime as _dt
import decimal
import re
from dataclasses import dataclass
from typing import Any

import oracledb

from text2sql.config import OracleConfig


_DDL_DML_RX = re.compile(
    r"^\s*(insert|update|delete|merge|create|drop|alter|truncate|grant|revoke|commit|rollback|call|begin)\b",
    re.IGNORECASE,
)
_FORBIDDEN_RX = re.compile(r";\s*\S", re.IGNORECASE)  # запрет цепочек statement'ов


class SQLValidationError(ValueError):
    """SQL отклонён политикой безопасности (не SELECT / содержит несколько statement'ов)."""


@dataclass
class QueryResult:
    columns: list[str]
    rows: list[list[Any]]
    truncated: bool
    row_count: int

    def to_dict(self) -> dict[str, Any]:
        return {
            "columns": self.columns,
            "rows": self.rows,
            "row_count": self.row_count,
            "truncated": self.truncated,
        }


def _normalize_sql(sql: str) -> str:
    cleaned = sql.strip()
    while cleaned.endswith(";"):
        cleaned = cleaned[:-1].rstrip()
    return cleaned


def validate_select(sql: str) -> str:
    """Бросает SQLValidationError, если SQL — не одиночный read-only запрос."""
    if not sql or not sql.strip():
        raise SQLValidationError("SQL пустой")
    cleaned = _normalize_sql(sql)
    if _FORBIDDEN_RX.search(cleaned):
        raise SQLValidationError("Запрещены несколько SQL statement'ов в одном запросе")
    if _DDL_DML_RX.match(cleaned):
        raise SQLValidationError("Разрешены только SELECT/WITH запросы")
    first = cleaned.split(None, 1)[0].lower()
    if first not in {"select", "with"}:
        raise SQLValidationError("SQL должен начинаться с SELECT или WITH")
    return cleaned


def _convert_value(value: Any) -> Any:
    """Преобразует значения Oracle в JSON-сериализуемые типы."""
    if value is None:
        return None
    if isinstance(value, decimal.Decimal):
        if value == value.to_integral_value():
            return int(value)
        return float(value)
    if isinstance(value, (_dt.datetime, _dt.date)):
        return value.isoformat()
    if isinstance(value, bytes):
        try:
            return value.decode("utf-8", errors="replace")
        except Exception:
            return repr(value)
    return value


class OracleClient:
    """Тонкая обёртка над oracledb для одноразовых SELECT-запросов."""

    def __init__(self, cfg: OracleConfig, max_rows: int = 200):
        self._cfg = cfg
        self._max_rows = max_rows

    def execute_select(self, sql: str, max_rows: int | None = None) -> QueryResult:
        cleaned = validate_select(sql)
        limit = max_rows if max_rows is not None else self._max_rows
        with oracledb.connect(
            user=self._cfg.username,
            password=self._cfg.password,
            dsn=self._cfg.dsn,
        ) as conn:
            with conn.cursor() as cur:
                cur.execute(cleaned)
                columns: list[str] = [str(d[0]) for d in (cur.description or [])]
                rows: list[list[Any]] = []
                truncated = False
                for idx, row in enumerate(cur):
                    if idx >= limit:
                        truncated = True
                        break
                    rows.append([_convert_value(v) for v in row])
        return QueryResult(
            columns=columns,
            rows=rows,
            truncated=truncated,
            row_count=len(rows),
        )

    def ping(self) -> bool:
        """Проверяет, что соединение работает."""
        with oracledb.connect(
            user=self._cfg.username,
            password=self._cfg.password,
            dsn=self._cfg.dsn,
        ) as conn:
            with conn.cursor() as cur:
                cur.execute("SELECT 1 FROM DUAL")
                cur.fetchone()
        return True

