"""Sanity-проверки результатов SQL-запроса."""

from __future__ import annotations

from typing import Any

from text2sql.db import QueryResult


def validate_result(
    result: QueryResult,
    expectations: dict[str, Any] | None = None,
) -> dict[str, Any]:
    """Проверяет результат на разумные характеристики.

    Поддерживаемые expectations:
        min_rows (int) — минимальное число строк (по умолчанию 1).
        max_rows (int) — максимальное число строк (если нужно поймать утечку выборки).
        non_null_columns (list[str]) — столбцы, которые во всех строках не должны быть NULL.
        value_ranges (dict[str, [min, max]]) — числовой диапазон значений столбца.
        expected_columns (list[str]) — ожидаемый набор имён колонок (по подстроке).

    Возвращает структуру: {ok, issues, summary}.
    """
    expectations = expectations or {}
    issues: list[str] = []

    rows = result.rows
    columns = result.columns
    col_index = {c.upper(): i for i, c in enumerate(columns)}

    min_rows = int(expectations.get("min_rows", 1))
    if len(rows) < min_rows:
        issues.append(f"Слишком мало строк: {len(rows)} < {min_rows}")

    if "max_rows" in expectations:
        max_rows = int(expectations["max_rows"])
        if len(rows) > max_rows:
            issues.append(f"Слишком много строк: {len(rows)} > {max_rows}")

    for col in expectations.get("non_null_columns", []) or []:
        idx = col_index.get(str(col).upper())
        if idx is None:
            issues.append(f"Колонка {col} отсутствует в результате")
            continue
        nulls = sum(1 for r in rows if r[idx] is None)
        if nulls:
            issues.append(f"Колонка {col} содержит {nulls} NULL-значений")

    ranges = expectations.get("value_ranges") or {}
    if isinstance(ranges, dict):
        for col, bounds in ranges.items():
            idx = col_index.get(str(col).upper())
            if idx is None:
                issues.append(f"Колонка {col} отсутствует, диапазон не проверен")
                continue
            try:
                lo, hi = bounds  # type: ignore[misc]
            except Exception:
                issues.append(f"Неверный формат диапазона для {col}: {bounds!r}")
                continue
            for r in rows:
                v = r[idx]
                if v is None:
                    continue
                try:
                    fv = float(v)
                except (TypeError, ValueError):
                    continue
                if lo is not None and fv < float(lo):
                    issues.append(f"{col}={fv} меньше нижней границы {lo}")
                    break
                if hi is not None and fv > float(hi):
                    issues.append(f"{col}={fv} больше верхней границы {hi}")
                    break

    for col in expectations.get("expected_columns", []) or []:
        if not any(str(col).upper() in c.upper() for c in columns):
            issues.append(f"Ожидаемая колонка {col} не найдена среди {columns}")

    summary = {
        "row_count": result.row_count,
        "columns": columns,
        "truncated": result.truncated,
    }
    return {"ok": not issues, "issues": issues, "summary": summary}

