"""Тест цикла агента: фейковый LLM + фейковый Oracle."""

from __future__ import annotations

import json
from types import SimpleNamespace
from typing import Any

from text2sql.agent import Text2SQLAgent
from text2sql.config import AppConfig, LLMConfig, OracleConfig
from text2sql.db import QueryResult


def _msg(content: str | None = None, tool_calls: list[dict] | None = None) -> Any:
    tcs = None
    if tool_calls:
        tcs = []
        for i, tc in enumerate(tool_calls):
            tcs.append(
                SimpleNamespace(
                    id=f"call_{i}",
                    function=SimpleNamespace(
                        name=tc["name"],
                        arguments=json.dumps(tc.get("args", {}), ensure_ascii=False),
                    ),
                )
            )
    return SimpleNamespace(content=content, tool_calls=tcs)


class FakeLLM:
    """Фейковый OpenAI client — отдаёт заранее заданные ответы по очереди."""

    def __init__(self, scripted: list[Any]):
        self._scripted = list(scripted)
        self.calls: list[dict[str, Any]] = []
        self.chat = SimpleNamespace(completions=SimpleNamespace(create=self._create))

    def _create(self, **kwargs: Any) -> Any:
        self.calls.append(kwargs)
        msg = self._scripted.pop(0)
        return SimpleNamespace(choices=[SimpleNamespace(message=msg)])


class FakeOracle:
    def __init__(self, result: QueryResult):
        self.result = result
        self.executed: list[str] = []

    def execute_select(self, sql: str, max_rows: int | None = None) -> QueryResult:
        self.executed.append(sql)
        return self.result


def _cfg() -> AppConfig:
    return AppConfig(
        oracle=OracleConfig(username="u", password="p", dsn="d"),
        llm=LLMConfig(api_key="k", base_url="http://x", sql_model="m", response_model="m"),
        max_agent_steps=5,
    )


def test_agent_happy_path() -> None:
    fake_result = QueryResult(
        columns=["TOTAL"], rows=[[123456.78]], truncated=False, row_count=1
    )
    llm = FakeLLM(
        scripted=[
            _msg(
                tool_calls=[
                    {
                        "name": "execute_sql",
                        "args": {"sql": "SELECT SUM(PNL_SUM) AS TOTAL FROM client_product"},
                    }
                ]
            ),
            _msg(
                tool_calls=[
                    {
                        "name": "final_answer",
                        "args": {
                            "text": "Общий доход составил 123 456.78 руб.",
                            "supporting_data": {"total": 123456.78},
                        },
                    }
                ]
            ),
        ]
    )
    agent = Text2SQLAgent(
        config=_cfg(),
        oracle_client=FakeOracle(fake_result),  # type: ignore[arg-type]
        openai_client=llm,  # type: ignore[arg-type]
        log=lambda _msg: None,
    )

    out = agent.answer("Какой общий доход?")
    assert "123 456.78" in out.answer
    assert out.supporting_data == {"total": 123456.78}
    assert len(out.sql_executed) == 1
    assert "PNL_SUM" in out.sql_executed[0]


def test_agent_recovers_from_sql_error() -> None:
    fake_result = QueryResult(
        columns=["C"], rows=[[1]], truncated=False, row_count=1
    )
    llm = FakeLLM(
        scripted=[
            # шаг 1: невалидный SQL (DROP) — должен получить error в tool result
            _msg(
                tool_calls=[
                    {"name": "execute_sql", "args": {"sql": "DROP TABLE x"}}
                ]
            ),
            # шаг 2: корректный SQL
            _msg(
                tool_calls=[
                    {"name": "execute_sql", "args": {"sql": "SELECT 1 AS C FROM dual"}}
                ]
            ),
            # шаг 3: final
            _msg(
                tool_calls=[
                    {"name": "final_answer", "args": {"text": "Готово: 1"}}
                ]
            ),
        ]
    )
    agent = Text2SQLAgent(
        config=_cfg(),
        oracle_client=FakeOracle(fake_result),  # type: ignore[arg-type]
        openai_client=llm,  # type: ignore[arg-type]
        log=lambda _msg: None,
    )

    out = agent.answer("test")
    assert "Готово" in out.answer
    # из двух SQL только второй должен был успешно выполниться
    assert len(out.sql_executed) == 1
    assert "SELECT 1" in out.sql_executed[0]


def test_agent_validate_result_before_final() -> None:
    fake_result = QueryResult(
        columns=["TOTAL"], rows=[[42]], truncated=False, row_count=1
    )
    llm = FakeLLM(
        scripted=[
            _msg(
                tool_calls=[
                    {
                        "name": "execute_sql",
                        "args": {"sql": "SELECT 42 AS TOTAL FROM dual"},
                    }
                ]
            ),
            _msg(
                tool_calls=[
                    {
                        "name": "validate_result",
                        "args": {"expectations": {"min_rows": 1, "non_null_columns": ["TOTAL"]}},
                    }
                ]
            ),
            _msg(
                tool_calls=[
                    {"name": "final_answer", "args": {"text": "Ответ: 42"}}
                ]
            ),
        ]
    )
    agent = Text2SQLAgent(
        config=_cfg(),
        oracle_client=FakeOracle(fake_result),  # type: ignore[arg-type]
        openai_client=llm,  # type: ignore[arg-type]
        log=lambda _msg: None,
    )
    out = agent.answer("Q")
    assert out.answer == "Ответ: 42"


def test_agent_plain_text_terminates_loop() -> None:
    """Если модель не делает tool call — её content становится ответом."""
    fake_result = QueryResult(columns=[], rows=[], truncated=False, row_count=0)
    llm = FakeLLM(scripted=[_msg(content="Прямой ответ без tools")])
    agent = Text2SQLAgent(
        config=_cfg(),
        oracle_client=FakeOracle(fake_result),  # type: ignore[arg-type]
        openai_client=llm,  # type: ignore[arg-type]
        log=lambda _msg: None,
    )
    out = agent.answer("Q")
    assert "Прямой ответ" in out.answer

